1731→            const int32_t *out_shift,
1732→            const int32_t *out_scale,
1733→            const int32_t in_offset,    //value is in the range of [-127, 128]
1734→            const int32_t out_offset,   //value is in the range of [-128, 127]
1735→            const int32_t act_min,
1736→            const int32_t act_max,
1737→            const int32_t num_col_a,
1738→            const int32_t *contri_buf,
1739→            int8_t *out)
1740→{
1741→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
1742→    // 4x2 tiled vd4dots GEMM: 4 output channels x 2 pixels per tile, LMUL=M2
1743→    // Halves pixel data reloads compared to v2 (2x2 tile, LMUL=M4)
1744→    (void)in_offset;
1745→
1746→    /* set up the second output pointers */
1747→    int8_t *out_0 = out;
1748→    int8_t *out_1 = out_0 + out_tensor_ch;
1749→    const int8_t *ptr_a0 = input_a;
1750→    long vl;
1751→
1752→    long maxvl_per_loop;
1753→    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
1754→
1755→    // Register allocation (LMUL=M2):
1756→    // Accumulators: v0(ch0*pix0), v2(ch0*pix1), v4(ch1*pix0), v6(ch1*pix1),
1757→    //               v8(ch2*pix0), v10(ch2*pix1), v12(ch3*pix0), v14(ch3*pix1)
1758→    // Load buffers: v16(pix0), v18(pix1), v20(wt0), v22(wt1), v24(wt2), v26(wt3)
1759→    // Scratch: v28-v31
1760→
1761→    for (long cur_row = 0; (cur_row + 4) <= out_tensor_ch; cur_row += 4)
1762→    {
1763→        /* setup pointers for B (im2col columns / pixels) */
1764→        const int8_t *ptr_b0 = input_b;
1765→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1766→
1767→        /* setup pointers for A (weight rows / channels) */
1768→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1769→        const int8_t *ptr_a2 = ptr_a1 + num_col_a;
1770→        const int8_t *ptr_a3 = ptr_a2 + num_col_a;
1771→
1772→        //init the 8 accumulators
1773→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
1774→        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1775→        NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
1776→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1777→        NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0x0);
1778→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
1779→        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
1780→        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
1781→        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
1782→
1783→        long col_count = num_col_a;
1784→        while(col_count >= maxvl_per_loop)
1785→        {
1786→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
1787→            // Load 2 pixel columns (reused across all 4 weight rows)
1788→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
1789→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
1790→            // Load 4 weight rows
1791→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
1792→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
1793→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
1794→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
1795→            ptr_a0 += vl;
1796→            ptr_a1 += vl;
1797→            ptr_a2 += vl;
1798→            ptr_a3 += vl;
1799→            ptr_b0 += vl;
1800→            ptr_b1 += vl;
1801→            col_count -= vl;
1802→
1803→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
1804→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);  //ch0*pix0
1805→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);  //ch0*pix1
1806→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);  //ch1*pix0
1807→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);  //ch1*pix1
1808→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);  //ch2*pix0
1809→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);  //ch2*pix1
1810→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);  //ch3*pix0
1811→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);  //ch3*pix1
1812→        }
1813→
1814→        //extra process for the case of elements to be dot producted is not a mutiple of 4
1815→        if(col_count > 0)
1816→        {
1817→            //clean pixel buffers to avoid junk in tail affecting vd4dots
1818→            long tmp_avl;
1819→            tmp_avl = col_count + 3;
1820→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
1821→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
1822→            NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0);
1823→
1824→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
1825→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
1826→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
1827→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
1828→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
1829→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
1830→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
1831→            ptr_a0 += vl;
1832→            ptr_a1 += vl;
1833→            ptr_a2 += vl;
1834→            ptr_a3 += vl;
1835→
1836→            vl = (vl + 3) >> 2;
1837→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
1838→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);
1839→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);
1840→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);
1841→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);
1842→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);
1843→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);
1844→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);
1845→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);
1846→        }
1847→
1848→        // === Reduction epilogue: 8 vredsum → pack to VL=4 → requantize ===
1849→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1850→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
1851→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
1852→
1853→        // Reduce 8 accumulators to scalars in element [0]
1854→        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0 → v16[0]
1855→        NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0 → v17[0]
1856→        NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0 → v18[0]
1857→        NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0 → v19[0]
1858→        NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix1 → v20[0]
1859→        NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix1 → v21[0]
1860→        NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix1 → v22[0]
1861→        NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix1 → v23[0]
1862→
1863→        // Pack 4 scalars into VL=4 vectors via vslideup
1864→        // pix0: v16 = [ch0, ch1, ch2, ch3]
1865→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1866→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
1867→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
1868→        NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1869→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
1870→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
1871→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1872→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
1873→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
1874→
1875→        // v16 = pix0 [ch0,ch1,ch2,ch3], v20 = pix1 [ch0,ch1,ch2,ch3]
1876→
1877→        //add extra contribution back
1878→        NDS_VEC_VLE32_V(NDS_VEC_V24, contri_buf);
1879→        contri_buf += vl;
1880→        NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
1881→        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V24);
1882→
1883→        //===== Quantize down =====
1884→        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
1885→        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
1886→        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
1887→
1888→        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V3);
1889→        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V20, NDS_VEC_V3);
1890→        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
1891→        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
1892→        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
1893→        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
1894→
1895→        // Add offset
1896→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
1897→        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
1898→
1899→        // Clamp the result
1900→        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
1901→        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
1902→        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
1903→        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
1904→
1905→        //narrowing and store the results
1906→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
1907→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1908→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1909→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1910→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1911→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1912→        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
1913→        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
1914→        out_0 += 4;
1915→        out_1 += 4;
1916→        out_scale += 4;
1917→        out_shift += 4;
1918→
1919→        ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
1920→    }
1921→
1922→    // === Handle remaining 2 channels (if out_tensor_ch % 4 >= 2) ===
1923→    if ((out_tensor_ch & 0x3) >= 2)
1924→    {
1925→        const int8_t *ptr_b0 = input_b;
1926→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1927→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1928→
1929→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1930→        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1931→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1932→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
1933→        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
1934→
1935→        long maxvl_m4;
1936→        NDS_VEC_VSETVLI(maxvl_m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1937→
1938→        long col_count = num_col_a;
1939→        while(col_count >= maxvl_m4)
1940→        {
1941→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
