1944→            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1945→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
1946→            ptr_a0 += vl;
1947→            ptr_a1 += vl;
1948→            ptr_b0 += vl;
1949→            ptr_b1 += vl;
