1957→        }
1958→
1959→        if(col_count > 0)
1960→        {
1961→            long tmp_avl = col_count + 3;
1962→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1963→            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
1964→            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);
1965→
1966→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1967→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1968→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1969→            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1970→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
