1974→            vl = (vl + 3) >> 2;
1975→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1976→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);
1977→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
1978→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);
1979→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);
