1989→
1990→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1991→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
1992→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V1, NDS_VEC_V3, 1);
